// On-demand digest: pulls everything since the last known digest date.
// Update LAST_DIGEST_DATE each time you run this, to the date of the last successful pull.
const LAST_DIGEST_DATE = '2026-06-26';

const now = new Date();
const today = now.toISOString().split('T')[0];
const fromDate = LAST_DIGEST_DATE;
const runStamp = now.toISOString().replace(/[:.]/g, '-');

return [{
  json: {
    fromDate: fromDate,
    toDate: today,
    dateLabel: today,
    branchName: 'daily/' + today + '-' + runStamp.slice(11, 16),
    filePath: 'journal/' + fromDate + '_to_' + today + '.md'
  }
}];

const PATTERNS = {
  scrum:         /scrum.*ai|ai.*scrum|scrum.*sales|scrum.*mktg|scrum.*marketing/i,
  amazon_nurture:/amazon.*nurtur|nurtur.*amazon|nurture.*sequence/i,
  ai_progress:   /discussion.*ai.*progress|weekly.*discussion.*ai|ai.*progress/i,
  sales_marketing:/sales.*marketing|marketing.*sales|sales.*mktg/i,
  general_ai:    /ai.*team|team.*ai|ai.*weekly|weekly.*ai|ai.*sync|sprint.*ai|ai.*sprint/i
};

const CATEGORY_LABELS = {
  scrum: 'AI Scrum',
  amazon_nurture: 'Amazon Nurture Sequence',
  ai_progress: 'AI Progress Discussions',
  sales_marketing: 'Sales & Marketing',
  general_ai: 'General AI Meetings'
};

const transcripts = $input.first().json?.data?.transcripts || [];
const byCategory = {};
let total = 0;

for (const t of transcripts) {
  if (!t || !t.title) continue;
  let category = null;
  for (const [cat, pattern] of Object.entries(PATTERNS)) {
    if (pattern.test(t.title)) { category = cat; break; }
  }
  if (!category) continue;
  if (!byCategory[category]) byCategory[category] = [];
  byCategory[category].push(t);
  total++;
}

if (total === 0) {
  return [{ json: { noMeetings: true, dateLabel: $('Build Date Window').item.json.dateLabel } }];
}

let meetingContext = '';
for (const [cat, meetings] of Object.entries(byCategory)) {
  meetingContext += '\n\n### ' + (CATEGORY_LABELS[cat] || cat) + ' (' + meetings.length + ' meeting(s))\n';
  for (const m of meetings) {
    meetingContext += '\n**' + m.title + '** (' + (m.date ? new Date(m.date).toDateString() : 'n/a') + ', ' + Math.round(m.duration || 0) + 'min)\n';
    if (m.summary?.short_summary) meetingContext += 'Summary: ' + m.summary.short_summary + '\n';
    if (m.summary?.action_items)  meetingContext += 'Action items:\n' + m.summary.action_items + '\n';
    if (m.summary?.keywords)      meetingContext += 'Keywords: ' + (Array.isArray(m.summary.keywords) ? m.summary.keywords.join(', ') : m.summary.keywords) + '\n';
    if (m.participants)           meetingContext += 'Participants: ' + (Array.isArray(m.participants) ? m.participants.join(', ') : m.participants) + '\n';
  }
}

const dw = $('Build Date Window').item.json;
return [{
  json: {
    noMeetings: false,
    meetingContext: meetingContext.trim(),
    totalMeetings: total,
    dateLabel: dw.dateLabel,
    branchName: dw.branchName,
    filePath: dw.filePath
  }
}];

const claudeResp = $input.first().json;
const markdown = claudeResp?.content?.[0]?.text || '';
const meta = $('Build Claude Prompt').item.json;
return [{
  json: {
    markdownContent: markdown,
    branchName: meta.branchName,
    filePath: meta.filePath,
    dateLabel: meta.dateLabel,
    totalMeetings: meta.totalMeetings
  }
}];
